const places = items[0].json.places || [];
const keyword = $('Code in JavaScript').first().json.keyword.toLowerCase();

// Keywords that indicate a real BBQ restaurant
const bbqIndicators = ['bbq', 'barbecue', 'barbeque', 'smokehouse', 'smoke pit', 'smoked', 'brisket', 'ribs'];

const filtered = places.map(place => {
  const name = (place.displayName?.text || '').toLowerCase();
  const summary = (place.editorialSummary?.text || '').toLowerCase();
  const types = (place.types || []).join(' ').toLowerCase();

  // Calculate relevance score
  let score = 0;

  // Check if name contains BBQ-related terms
  for (const term of bbqIndicators) {
    if (name.includes(term)) score += 3;
    if (summary.includes(term)) score += 2;
  }

  // Check if it's classified as BBQ
  if (types.includes('bbq') || types.includes('barbecue')) score += 3;

  // Penalize generic names that don't suggest BBQ
  const genericNames = ['cafe', 'kitchen', 'grill', 'dock', 'backyard'];
  for (const term of genericNames) {
    if (name.includes(term) && score === 0) score -= 1;
  }

  return {
    ...place,
    relevanceScore: score
  };
});

// Sort by relevance, then by rating
const sorted = filtered
  .sort((a, b) => {
    if (b.relevanceScore !== a.relevanceScore) {
      return b.relevanceScore - a.relevanceScore;
    }
    return (b.rating || 0) - (a.rating || 0);
  });

return { json: { places: sorted } };
